from fastapi.responses import HTMLResponse


def render_business_page() -> HTMLResponse:
    return HTMLResponse("""<!doctype html><html lang='sr'><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Business · Balkan.works</title><style>body{margin:0;background:#fbfaf6;color:#092c26;font-family:system-ui}main{max-width:820px;margin:auto;padding:42px 20px}.brand{font-weight:900;font-size:24px;color:#092c26;text-decoration:none}.brand i{color:#ff6c37}.card{background:#fff;border:1px solid #d9e3dc;border-radius:16px;padding:24px;margin-top:24px;max-width:680px}h1{font:44px Georgia,serif;margin:10px 0}input,textarea{display:block;width:100%;padding:12px;margin:9px 0;border:1px solid #d9e3dc;border-radius:8px;font:inherit}button{background:#ff6c37;color:#fff;padding:12px 16px;border:0;border-radius:8px;font-weight:800;cursor:pointer}.muted{color:#62746e}.hidden{display:none}.firm{border-top:1px solid #d9e3dc;padding:14px 0}</style><main><a class='brand' href='/'>balkan<i>.</i>works</a><section id='signin' class='card'><h1>Poslovni panel</h1><p class='muted'>Prijavi se preko <a href='/account'>svog naloga</a>, zatim se vrati ovde.</p></section><section id='panel' class='hidden'><h1>Moje firme</h1><div class='card'><h2>Dodaj firmu</h2><input id='business-name' placeholder='Naziv firme'><input id='business-country' placeholder='Država (RS)'><input id='business-city' placeholder='Grad'><input id='business-address' placeholder='Adresa'><input id='business-tax' placeholder='PIB (opciono)'><textarea id='business-description' placeholder='Kratak opis firme'></textarea><button id='business-save'>Sačuvaj firmu</button><p class='muted' id='business-status'></p></div><div class='card' id='business-list'></div></section></main><script>const token=localStorage.getItem('balkan_access_token'),headers={'content-type':'application/json','authorization':'Bearer '+token};async function loadBusinesses(){if(!token)return;document.querySelector('#signin').classList.add('hidden');document.querySelector('#panel').classList.remove('hidden');const r=await fetch('/api/businesses',{headers});if(!r.ok)return;const rows=await r.json();document.querySelector('#business-list').innerHTML='<h2>Registrovane firme</h2>'+(rows.length?rows.map(x=>'<div class="firm"><b>'+x.name+'</b><p class="muted">'+x.city_name+', '+x.country_code+' · '+x.verification_status+'</p></div>').join(''):'<p class="muted">Još nema registrovanih firmi.</p>')}document.querySelector('#business-save').onclick=async()=>{const payload={name:document.querySelector('#business-name').value,country_code:document.querySelector('#business-country').value.toUpperCase(),city_name:document.querySelector('#business-city').value,address:document.querySelector('#business-address').value||null,tax_id:document.querySelector('#business-tax').value||null,description:document.querySelector('#business-description').value||null};const r=await fetch('/api/businesses',{method:'POST',headers,body:JSON.stringify(payload)}),d=await r.json();document.querySelector('#business-status').textContent=r.ok?'Firma je sačuvana i čeka verifikaciju.':(d.detail||'Greška');if(r.ok)loadBusinesses()};loadBusinesses()</script></html>""")
